local rs = game:GetService("RunService")
local lp = game.Players.LocalPlayer
local url = "https://github.com/lol9182828/Dances-lol/raw/refs/heads/main/Squidward%20Yell%202.mp3"

local function make_tool()
    local tool = Instance.new("Tool")
    tool.Name = "SQUIDWARD YELL 2"
    tool.RequiresHandle = false
    tool.Parent = lp.Backpack
    
    local s = Instance.new("Sound")
    s.Volume = 0.5
    s.Looped = true
    
    task.spawn(function()
        if writefile and request then
            if not isfile("squid_audio.mp3") then
                local r = request({Url = url, Method = "GET"})
                writefile("squid_audio.mp3", r.Body)
            end
            s.SoundId = getcustomasset("squid_audio.mp3")
        else
            s.SoundId = url
        end
    end)
    
    local conn
    tool.Equipped:Connect(function()
        local char = lp.Character
        if not char then return end
        local start = tick()
        local dur = AnimData[#AnimData].Time
        s.Parent = char:FindFirstChild("Head") or char.PrimaryPart
        s:Play()
        if char:FindFirstChild("Animate") then char.Animate.Disabled = true end
        for _, t in pairs(char.Humanoid:GetPlayingAnimationTracks()) do t:Stop(0) end
        local joints = {}
        for _, v in pairs(char:GetDescendants()) do
            if v:IsA("Motor6D") and v.Part1 then joints[v.Part1.Name] = v end
        end
        conn = rs.Stepped:Connect(function()
            local t = (tick() - start) % dur
            local k = AnimData[1]
            for i = 1, #AnimData do
                if AnimData[i].Time <= t then k = AnimData[i] else break end
            end
            for name, cf in pairs(k.Poses) do
                if joints[name] then joints[name].Transform = cf end
            end
        end)
    end)
    
    tool.Unequipped:Connect(function()
        if conn then conn:Disconnect() end
        s:Stop()
        local char = lp.Character
        if char then
            if char:FindFirstChild("Animate") then char.Animate.Disabled = false end
            for _, v in pairs(char:GetDescendants()) do
                if v:IsA("Motor6D") then v.Transform = CFrame.identity end
            end
        end
    end)
end

lp.CharacterAdded:Connect(function() task.wait(1) make_tool() end)
make_tool()
